import { describe, expect, test } from '@a0n/gnosis/test';

import { runFoilAdmissionShootout } from './foil-admission-shootout';

describe('gnosis FOIL admission shootout', () => {
  test('proves Triton preflight avoids verifier calls on rejected hotpath work', () => {
    const report = runFoilAdmissionShootout();

    expect(report.label).toBe('gnosis-foil-admission-shootout-v1');
    expect(report.leanTheorems).toContain(
      'Gnosis.PleromaAeonMonsterBridge.weighted_triton_avoided_cost_eq_dropped_cost'
    );
    expect(report.scenarioCount).toBe(5);
    expect(report.acceptedByBaseline).toBe(5);
    expect(report.acceptedByTritonGate).toBe(2);
    expect(report.baselineVerifierCalls).toBe(5);
    expect(report.tritonGateVerifierCalls).toBe(2);
    expect(report.avoidedVerifierCalls).toBe(3);
    expect(report.avoidedVerificationCost).toBe(31);
    expect(report.tritonGateMetrics.tritonPreflightDropped).toBe(3);
    expect(report.tritonGateMetrics.executedTopologies).toBe(2);
  });

  test('proves EHLA harvests gaps to achieve zero verifier calls on admitted work', () => {
    const report = runFoilAdmissionShootout();

    expect(report.acceptedByEHLA).toBe(5);
    expect(report.ehlaVerifierCalls).toBe(0); // Maximum speedup!
    expect(report.ehlaAvoidedVerifierCalls).toBe(5);
    expect(report.ehlaMetrics.harvestedTopologies).toBe(5);
    expect(report.ehlaMetrics.interpretationDebt).toBe(5);
    expect(report.leanTheorems).toContain(
      'Gnosis.EntropyHarvestingArchitecture.ehla_harvests_debt_as_propellant'
    );
  });

  test('keeps the hotpath escape hatch when no Triton admission is supplied', () => {
    const report = runFoilAdmissionShootout();

    expect(report.escapeHatchVerifierCalls).toBe(1);
    expect(report.tritonGateMetrics.admissionAttempts).toBe(5);
    expect(report.tritonGateMetrics.tritonPreflightAttempts).toBe(4);
    expect(report.tritonGateMetrics.verifierCalls).toBe(2);
  });
});
